/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn liter_llm_embedding_response_estimated_cost(this: *const liter_llm::EmbeddingResponse) -> f64 {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return 0.0;
    }
    let obj = unsafe { &*this };
    let result = obj.estimated_cost();
    result.unwrap_or(0.0)
}

